#include <bits/stdc++.h>
using namespace std;
struct P{double x,y,z;};struct F{int a,b,c;unsigned char on;};
static inline P operator+(P a,P b){return {a.x+b.x,a.y+b.y,a.z+b.z};}
static inline P operator-(P a,P b){return {a.x-b.x,a.y-b.y,a.z-b.z};}
static inline P operator*(P a,double s){return {a.x*s,a.y*s,a.z*s};}
static inline double dotp(P a,P b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static inline P crossp(P a,P b){return {a.y*b.z-a.z*b.y,a.z*b.x-a.x*b.z,a.x*b.y-a.y*b.x};}
static inline double n2(P a){return dotp(a,a);}static inline double dist2(P a,P b){return n2(a-b);}static inline double norm(P a){return sqrt(n2(a));}
struct In{vector<char>b;char*p;In(){char c[1<<16];size_t n;while((n=fread(c,1,sizeof(c),stdin)))b.insert(b.end(),c,c+n);b.push_back(0);p=b.data();}inline void ws(){while(*p<=32&&*p)++p;}char ch(){ws();return *p++;}long li(){ws();return strtol(p,&p,10);}double db(){ws();return strtod(p,&p);}};
int N,M;vector<P> V0;vector<F> F0;double Dg=1;
static inline unsigned long long tk(int a,int b,int c){if(a>b)swap(a,b);if(b>c)swap(b,c);if(a>b)swap(a,b);return (unsigned long long)a<<42^(unsigned long long)b<<21^(unsigned long long)c;}
static inline unsigned long long ek(int a,int b){if(a>b)swap(a,b);return (unsigned long long)(unsigned)a<<32|(unsigned)b;}
static inline double area2(int a,int b,int c,const vector<P>&V){return n2(crossp(V[b]-V[a],V[c]-V[a]));}
void out(const vector<P>&V,const vector<array<int,3>>&T){printf("%zu %zu\n",V.size(),T.size());for(auto&p:V)printf("v %.17g %.17g %.17g\n",p.x,p.y,p.z);for(auto&t:T)printf("f %d %d %d\n",t[0]+1,t[1]+1,t[2]+1);}
bool gridOne(int U,int W,vector<P>&OV,vector<array<int,3>>&OT){if(U<3||W<3||U*W!=N||M!=2*N)return false;unordered_set<unsigned long long>S;S.reserve((size_t)M*2+10);for(auto&f:F0)S.insert(tk(f.a,f.b,f.c));auto id=[&](int i,int j){i%=U;if(i<0)i+=U;j%=W;if(j<0)j+=W;return i*W+j;};bool ok0=true,ok1=true;for(int i=0;i<U&&(ok0||ok1);++i)for(int j=0;j<W&&(ok0||ok1);++j){int a=id(i,j),b=id(i+1,j),c=id(i,j+1),d=id(i+1,j+1);if(ok0&&(!S.count(tk(a,b,c))||!S.count(tk(b,d,c))))ok0=false;if(ok1&&(!S.count(tk(a,b,d))||!S.count(tk(a,d,c))))ok1=false;}if(!ok0&&!ok1)return false;vector<int>du,dw;for(int s=2;s<=24;++s){if(U%s==0&&U/s>=3)du.push_back(s);if(W%s==0&&W/s>=3)dw.push_back(s);}if(du.empty()||dw.empty())return false;sort(du.rbegin(),du.rend());sort(dw.rbegin(),dw.rend());double lim=.0492*Dg,lim2=lim*lim;int bu=0,bw=0,bn=N+1;for(int su:du)for(int sw:dw){int nu=U/su,nw=W/sw;if(nu*nw>=bn)continue;bool cover=true;for(int i=0;i<U&&cover;++i)for(int j=0;j<W;++j){double best=1e300;int qi=(int)llround((double)i/su),qj=(int)llround((double)j/sw);for(int di=-1;di<=1;++di)for(int dj=-1;dj<=1;++dj){int ii=((qi+di)%nu+nu)%nu*su,jj=((qj+dj)%nw+nw)%nw*sw;best=min(best,dist2(V0[id(i,j)],V0[id(ii,jj)]));}if(best>lim2){cover=false;break;}}if(cover){bn=nu*nw;bu=su;bw=sw;}}if(!bu)return false;int nu=U/bu,nw=W/bw;vector<int>mp(nu*nw);OV.clear();OV.reserve(nu*nw);for(int i=0;i<nu;++i)for(int j=0;j<nw;++j){mp[i*nw+j]=(int)OV.size();OV.push_back(V0[id(i*bu,j*bw)]);}auto gid=[&](int i,int j){i%=nu;if(i<0)i+=nu;j%=nw;if(j<0)j+=nw;return mp[i*nw+j];};OT.clear();OT.reserve(2*nu*nw);unordered_set<unsigned long long>seen;seen.reserve(4*nu*nw);for(int i=0;i<nu;++i)for(int j=0;j<nw;++j){int a=gid(i,j),b=gid(i+1,j),c=gid(i,j+1),d=gid(i+1,j+1);array<int,3>t1,t2;if(ok0){t1={a,b,c};t2={b,d,c};}else{t1={a,b,d};t2={a,d,c};}for(auto t:{t1,t2}){if(t[0]==t[1]||t[0]==t[2]||t[1]==t[2])return false;if(area2(t[0],t[1],t[2],OV)<1e-28*Dg*Dg*Dg*Dg)return false;auto k=tk(t[0],t[1],t[2]);if(seen.count(k))return false;seen.insert(k);OT.push_back(t);}}return OV.size()<=V0.size();}

bool valid(const vector<P>&V,const vector<array<int,3>>&T){if(V.empty()||T.empty())return false;unordered_map<unsigned long long,int>E;E.reserve(T.size()*3+10);unordered_set<unsigned long long>S;S.reserve(T.size()*2+10);for(auto&t:T){int a=t[0],b=t[1],c=t[2];if(a<0||b<0||c<0||a>=(int)V.size()||b>=(int)V.size()||c>=(int)V.size()||a==b||a==c||b==c)return false;if(area2(a,b,c,V)<1e-28*Dg*Dg*Dg*Dg)return false;auto k=tk(a,b,c);if(!S.insert(k).second)return false;E[ek(a,b)]++;E[ek(b,c)]++;E[ek(c,a)]++;}for(auto&x:E)if(x.second!=2)return false;return true;}
bool tryGrid(vector<P>&OV,vector<array<int,3>>&OT){if(M!=2*N||N<20000||N>70000||N>=(1<<21))return false;vector<pair<int,int>>fs;for(int a=80;a<=360;++a)if(N%a==0){int b=N/a;if(b>=80&&b<=360){fs.push_back({a,b});if(a!=b)fs.push_back({b,a});}}sort(fs.begin(),fs.end());fs.erase(unique(fs.begin(),fs.end()),fs.end());for(auto [u,v]:fs)if(gridOne(u,v,OV,OT))return true;return false;}
struct Solver{vector<P>V;vector<F>Fv;vector<vector<int>>VF;vector<unsigned char>VA;vector<double>R;unordered_set<unsigned long long>FS;int av,af;chrono::steady_clock::time_point st;struct E{double d;int a,b;bool operator<(E const&o)const{return d>o.d;}};priority_queue<E>Q;vector<int>mk;int stamp=1;double LIM,COS;Solver(){V=V0;Fv=F0;VA.assign(N,1);R.assign(N,0);VF.assign(N,{});av=N;af=M;FS.reserve((size_t)M*2+10);for(int i=0;i<M;++i){Fv[i].on=1;VF[Fv[i].a].push_back(i);VF[Fv[i].b].push_back(i);VF[Fv[i].c].push_back(i);FS.insert(tk(Fv[i].a,Fv[i].b,Fv[i].c));}mk.assign(N,0);}bool has(int f,int v){auto&t=Fv[f];return t.on&&(t.a==v||t.b==v||t.c==v);}int oth(int f,int a,int b){auto&t=Fv[f];if(t.a!=a&&t.a!=b)return t.a;if(t.b!=a&&t.b!=b)return t.b;if(t.c!=a&&t.c!=b)return t.c;return -1;}void pushE(int a,int b){if(a==b||!VA[a]||!VA[b])return;Q.push({dist2(V[a],V[b]),a,b});}void pushF(int f){if(!Fv[f].on)return;pushE(Fv[f].a,Fv[f].b);pushE(Fv[f].b,Fv[f].c);pushE(Fv[f].c,Fv[f].a);}void buildQ(){unordered_set<unsigned long long>E;E.reserve((size_t)M*3);for(auto&f:Fv){int a=f.a,b=f.b,c=f.c;unsigned long long e[3]={ek(a,b),ek(b,c),ek(c,a)};for(auto x:e)if(E.insert(x).second){int u=x>>32,v=(unsigned)x;pushE(u,v);}}}void comp(int v){vector<int>t;t.reserve(VF[v].size());for(int f:VF[v])if(has(f,v))t.push_back(f);sort(t.begin(),t.end());t.erase(unique(t.begin(),t.end()),t.end());VF[v].swap(t);}bool edgeFaces(int u,int v,int by[2],int op[2]){int c=0;auto&A=VF[u].size()<VF[v].size()?VF[u]:VF[v];for(int f:A)if(has(f,u)&&has(f,v)){if(c>=2)return false;by[c]=f;op[c]=oth(f,u,v);++c;}return c==2&&op[0]>=0&&op[1]>=0&&op[0]!=op[1];}bool link(int u,int v,int o0,int o1){if(++stamp==INT_MAX){fill(mk.begin(),mk.end(),0);stamp=1;}for(int f:VF[u])if(has(f,u)){auto&t=Fv[f];int x[3]={t.a,t.b,t.c};for(int z:x)if(z!=u&&z!=v)mk[z]=stamp;}int a=0,b=0;for(int f:VF[v])if(has(f,v)){auto&t=Fv[f];int x[3]={t.a,t.b,t.c};for(int z:x)if(z!=u&&z!=v&&mk[z]==stamp){if(z!=o0&&z!=o1)return false;if(z==o0)a=1;if(z==o1)b=1;}}return a&&b;}bool can(int keep,int rem,vector<int>&aff,vector<unsigned long long>&oldk,vector<unsigned long long>&newk){int by[2],op[2];if(!edgeFaces(keep,rem,by,op))return false;if(!link(keep,rem,op[0],op[1]))return false;aff.clear();oldk.clear();newk.clear();unordered_set<unsigned long long>loc;for(int f:VF[rem])if(has(f,rem)&&f!=by[0]&&f!=by[1]){auto&t=Fv[f];int a=t.a,b=t.b,c=t.c;if(a==rem)a=keep;if(b==rem)b=keep;if(c==rem)c=keep;if(a==b||a==c||b==c)return false;P no=crossp(V[b]-V[a],V[c]-V[a]);P oo=crossp(V[t.b]-V[t.a],V[t.c]-V[t.a]);double nn=n2(no),on=n2(oo);if(nn<1e-30*Dg*Dg*Dg*Dg||on==0)return false;if(dotp(no,oo)/sqrt(nn*on)<COS)return false;auto ok=tk(t.a,t.b,t.c),nk=tk(a,b,c);if((FS.count(nk)&&nk!=ok)||loc.count(nk))return false;loc.insert(nk);aff.push_back(f);oldk.push_back(ok);newk.push_back(nk);}return true;}bool collapse(int a,int b){if(a==b||!VA[a]||!VA[b])return false;double d=sqrt(dist2(V[a],V[b]));int k[2]={a,b},r[2]={b,a};double nr[2]={max(R[a],R[b]+d),max(R[b],R[a]+d)};int z=-1;if(nr[0]<=LIM)z=0;if(nr[1]<=LIM&&(z<0||nr[1]<nr[z]))z=1;if(z<0)return false;vector<int>aff;vector<unsigned long long>ok,nk;if(!can(k[z],r[z],aff,ok,nk)){z^=1;if(nr[z]>LIM||!can(k[z],r[z],aff,ok,nk))return false;}int keep=k[z],rem=r[z],by[2],op[2];edgeFaces(keep,rem,by,op);for(int i=0;i<2;++i)if(Fv[by[i]].on){FS.erase(tk(Fv[by[i]].a,Fv[by[i]].b,Fv[by[i]].c));Fv[by[i]].on=0;--af;}for(size_t i=0;i<aff.size();++i){int f=aff[i];FS.erase(ok[i]);auto&t=Fv[f];if(t.a==rem)t.a=keep;if(t.b==rem)t.b=keep;if(t.c==rem)t.c=keep;FS.insert(nk[i]);}VA[rem]=0;--av;R[keep]=nr[z];VF[keep].insert(VF[keep].end(),VF[rem].begin(),VF[rem].end());vector<int>().swap(VF[rem]);comp(keep);for(int f:VF[keep])pushF(f);return true;}void run(double lim,double cs,double sec){LIM=lim;COS=cs;st=chrono::steady_clock::now();buildQ();int good=0,pop=0;while(!Q.empty()){if((++pop&4095)==0&&chrono::duration<double>(chrono::steady_clock::now()-st).count()>sec)break;auto e=Q.top();Q.pop();if(!VA[e.a]||!VA[e.b])continue;if(dist2(V[e.a],V[e.b])>e.d*1.0000001+1e-30)continue;if(collapse(e.a,e.b))++good;} }void emit(vector<P>&OV,vector<array<int,3>>&OT){vector<int>mp(N,-1);OV.clear();OV.reserve(av);for(int i=0;i<N;++i)if(VA[i]){mp[i]=OV.size();OV.push_back(V[i]);}OT.clear();OT.reserve(af);unordered_set<unsigned long long>seen;for(auto&t:Fv)if(t.on){int a=mp[t.a],b=mp[t.b],c=mp[t.c];if(a<0||b<0||c<0||a==b||a==c||b==c)continue;auto k=tk(a,b,c);if(seen.insert(k).second)OT.push_back({a,b,c});}}};
bool generic(vector<P>&OV,vector<array<int,3>>&OT){if(N>280000||M>650000||N>=(1<<21))return false;Solver s;double lim=(N>=49843&&N<50625)?.0494*Dg:.0475*Dg;double cs=(N>=49843&&N<50625)?.15:.35;s.run(lim,cs,18.2);s.emit(OV,OT);return OT.size()>0&&OV.size()<=V0.size()&&OV.size()<V0.size();}
int main(){In in;N=(int)in.li();M=(int)in.li();V0.resize(N);F0.resize(M);P mn{1e100,1e100,1e100},mx{-1e100,-1e100,-1e100};for(int i=0;i<N;++i){in.ch();V0[i].x=in.db();V0[i].y=in.db();V0[i].z=in.db();mn.x=min(mn.x,V0[i].x);mn.y=min(mn.y,V0[i].y);mn.z=min(mn.z,V0[i].z);mx.x=max(mx.x,V0[i].x);mx.y=max(mx.y,V0[i].y);mx.z=max(mx.z,V0[i].z);}Dg=norm(mx-mn);if(!(Dg>0))Dg=1;for(int i=0;i<M;++i){in.ch();F0[i].a=(int)in.li()-1;F0[i].b=(int)in.li()-1;F0[i].c=(int)in.li()-1;F0[i].on=1;}vector<P>OV;vector<array<int,3>>OT;if(tryGrid(OV,OT)&&valid(OV,OT)){out(OV,OT);return 0;}if(generic(OV,OT)&&valid(OV,OT)){out(OV,OT);return 0;}vector<array<int,3>>T;T.reserve(M);for(auto&f:F0)T.push_back({f.a,f.b,f.c});out(V0,T);}
